SELECT t.ticker, t.time FROM `tav2_bq.ticker` AS t WHERE (t.time >= '2020-01-01' AND t.time <= '2026-04-03') AND ((t.Volume_3M_P50*t.Price/ NULLIF(t.Inflation_7, 0))>1400000000.0) AND (t.Risk_Rating <= 5) AND (t.D_RSI / NULLIF(t.D_RSI_T1, 0) > 0.68) AND (t.D_RSI > 0.46) AND (t.D_RSI < 0.78) AND (t.D_RSI_Min3M < 0.34) AND (t.D_RSI_Min1W > 0.11) AND (t.D_RSI_Min1W/ NULLIF(t.D_RSI_Min3M, 0) > 1.26) AND (t.D_RSI_Min1W_Close/ NULLIF(t.D_RSI_Min3M_Close, 0) < 1.85) AND (t.FSCORE > 4.0) AND (t.PE< 13.0) AND (t.PE>5.6) AND (t.PB < 3.1) AND (t.PB > 0.5) AND (t.ROE_Min5Y > 0.045) AND (t.PCF <34.0) AND (t.PCF>3.5) AND ((t.Cash_P0/ (t.LtDebt_P0+1) > 0.038) OR (ABS(t.IntCov_P0) > 6.0)) AND ((t.CF_OA_5Y/ NULLIF(t.OShares, 0))> 10000.0) AND (t.NP_P0/ NULLIF(t.NP_P4, 0) >=1.15) ORDER BY t.ticker, t.time